SELECT , A.RNUM FROM ( SELECT , ROWNUM RNUM FROM ( SELECT
FROM FCT.TB_CONFIG_ROUTE_MST A
WHERE 1=1 AND A.SAUDIT_FLAG != '정상'
AND A.SOFFICECODE IN ( SELECT DISTINCT LVLR.SLVL_CD FROM MST.TB_LVL_ROLE LVLR , MST.TB_LVL_SUB_CD LVLS , MST.TB_LVL_MST LVLM WHERE LVLR.SPOFFICECODE = LVLS.SLOFFICECODE AND LVLS.SLVL_CD = LVLM.SSVC_OBJ_CD AND LVLM.NLVL_MST_SEQ IN
#{item.nlvlSeq}
)
ORDER BY A.DMODIFY_DT DESC ) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

